package com.theyawns.framework.dlq;

/**
 * Holds the current fault injection state for DLQ demo scenarios.
 *
 * <p>When enabled, saga listeners check this state at the top of each event handler
 * and throw a {@link RuntimeException} if fault injection is active. This triggers
 * the circuit breaker exhaustion path, which routes the event to the DLQ.
 *
 * <p>Thread-safe via volatile fields. Injected into saga listeners as an optional
 * dependency ({@code @Autowired(required = false)}).
 *
 * @author Generated by Claude Code
 * @since 3.0
 */
public class FaultInjectionState {

    private volatile boolean enabled;
    private volatile String failureMessage = "Simulated fault injection failure";

    /**
     * Returns whether fault injection is currently enabled.
     *
     * @return true if faults should be injected
     */
    public boolean isEnabled() {
        return enabled;
    }

    /**
     * Enables or disables fault injection.
     *
     * @param enabled true to enable fault injection
     */
    public void setEnabled(final boolean enabled) {
        this.enabled = enabled;
    }

    /**
     * Returns the failure message used when injecting faults.
     *
     * @return the failure message
     */
    public String getFailureMessage() {
        return failureMessage;
    }

    /**
     * Sets the failure message used when injecting faults.
     *
     * @param failureMessage the failure message
     */
    public void setFailureMessage(final String failureMessage) {
        this.failureMessage = failureMessage != null ? failureMessage : "Simulated fault injection failure";
    }

    /**
     * Checks if fault injection is enabled and throws if so.
     *
     * <p>Call this at the top of saga listener event handlers:
     * <pre>{@code
     * if (faultInjection != null) {
     *     faultInjection.checkAndThrow();
     * }
     * }</pre>
     *
     * @throws RuntimeException if fault injection is enabled
     */
    public void checkAndThrow() {
        if (enabled) {
            throw new RuntimeException(failureMessage);
        }
    }
}
